791	This section packages the standard basic-open cover of an affine open into the project's conventions. Given a subset $s \subseteq \mathcal O_X(U)$ spanning the unit ideal, the basic opens $D(f)$ for $f \in s$ form a cover of $U$. All members and their finite intersections are again affine.
792	
793	\begin{definition}[Basic-open cover]
794	  \label{def:Scheme_basicOpenCover}
795	  \lean{AlgebraicGeometry.Scheme.basicOpenCover}
796	  Let $U$ be an open of $X$ and $s \subseteq \mathcal O_X(U)$. The basic-open cover indexed by $s$ sends $f \in s$ to $D(f)$.
797	\end{definition}
798	
799	\begin{theorem}[Supremum equality]
800	  \label{thm:Scheme_basicOpenCover_supr_of_span_eq_top}
801	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_supr_of_span_eq_top}
802	  \uses{def:Scheme_basicOpenCover}
803	  If $U$ is affine and $s$ spans the unit ideal, then $\bigsqcup_{f \in s} D(f) = U$.
804	\end{theorem}
805	
806	\begin{proof}
807	  Standard characterisation: the union of basic opens equals the whole affine if and only if the generators span the unit ideal.
808	\end{proof}
809	
810	\begin{theorem}[Affine membership]
811	  \label{thm:Scheme_basicOpenCover_isAffineOpen}
812	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isAffineOpen}
813	  \uses{def:Scheme_basicOpenCover}
814	  If $U$ is affine, then every member $D(f)$ of the basic-open cover is affine.
815	\end{theorem}
816	
817	\begin{proof}
818	  The basic open of an affine scheme is affine.
819	\end{proof}
820	
821	\begin{theorem}[Existence producer from basic-open evidence]
822	  \label{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen}
823	  \lean{AlgebraicGeometry.Scheme.hasAffineCechAcyclicCover_of_basicOpen}
824	  \uses{def:Scheme_HasAffineCechAcyclicCover, def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_supr_of_span_eq_top}
825	  If for every affine open $U$ there exists a spanning subset $s \subseteq \mathcal O_X(U)$ such that the basic-open cover by $s$ is Čech-acyclic and carries a comparison isomorphism, then $\HasAffineCechAcyclicCover$ holds.
826	\end{theorem}
827	
828	\begin{proof}
829	  Bundle the basic-open cover together with the supremum equality into the existential shape required by the carrier.
830	\end{proof}
831	
832	\begin{theorem}[Curve specialisation]
833	  \label{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen_curve}
834	  \lean{AlgebraicGeometry.Scheme.hasAffineCechAcyclicCover_of_basicOpen_curve}
835	  \uses{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen}
836	  Same statement specialised to the structure sheaf $\mathcal O_C$.
837	\end{theorem}
838	
839	\begin{proof}
840	  Direct application.
841	\end{proof}
