843	\subsection{Intersection helpers}
844	
845	Finite intersections of basic opens are again basic opens of a product.
846	
847	\begin{theorem}[Pairwise intersection]
848	  \label{thm:Scheme_basicOpenCover_inter_eq_basicOpen_mul}
849	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_inter_eq_basicOpen_mul}
850	  \uses{def:Scheme_basicOpenCover}
851	  For $f, g \in s$, $D(f) \cap D(g) = D(fg)$.
852	\end{theorem}
853	
854	\begin{proof}
855	  Standard identity for basic opens.
856	\end{proof}
857	
858	\begin{theorem}[Pairwise intersection is affine]
859	  \label{thm:Scheme_basicOpenCover_inter_isAffineOpen}
860	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_inter_isAffineOpen}
861	  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_inter_eq_basicOpen_mul}
862	  If $U$ is affine, then $D(f) \cap D(g)$ is affine.
863	\end{theorem}
864	
865	\begin{proof}
866	  By the previous theorem it is a single basic open.
867	\end{proof}
868	
869	\begin{theorem}[$n$-ary intersection]
870	  \label{thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod}
871	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_eq_basicOpen_prod}
872	  \uses{def:Scheme_basicOpenCover}
873	  For a non-empty finite subset $t \subseteq s$,
874	  \[
875	    \bigcap_{f \in t} D(f) \;=\; D\Bigl(\prod_{f \in t} f\Bigr).
876	  \]
877	\end{theorem}
878	
879	\begin{proof}
880	  By induction on the finite subset, using the binary case.
881	\end{proof}
882	
883	\begin{theorem}[$n$-ary intersection is affine]
884	  \label{thm:Scheme_basicOpenCover_finset_inf_isAffineOpen}
885	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_isAffineOpen}
886	  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod}
887	  If $U$ is affine, then $\bigcap_{f \in t} D(f)$ is affine.
888	\end{theorem}
889	
890	\begin{proof}
891	  By the previous theorem it is a single basic open.
892	\end{proof}
893	
894	\begin{theorem}[$n$-ary intersection inclusion]
895	  \label{thm:Scheme_basicOpenCover_finset_inf_le}
896	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_le}
897	  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod}
898	  For a non-empty finite subset $t \subseteq s$, $\bigcap_{f \in t} D(f) \subseteq U$.
899	\end{theorem}
900	
901	\begin{proof}
902	  A basic open is contained in the ambient affine.
903	\end{proof}
904	
905	\begin{theorem}[$n$-ary intersection as a localization]
906	  \label{thm:Scheme_basicOpenCover_finset_inf_isLocalization}
907	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_isLocalization}
908	  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le}
909	  Let $U$ be affine and $t$ a non-empty finite subset of $s$, and write $V = \bigcap_{f \in t} D(f)$ and $g = \prod_{f \in t} f$. Then $\mathcal O_X(V)$ is the localization of $\mathcal O_X(U)$ away from $g$, with the algebra structure given by the presheaf restriction map.
910	\end{theorem}
911	
912	\begin{proof}
913	  Apply the standard localization theorem for basic opens, using the equality and inclusion theorems above.
914	\end{proof}
